import React, { useEffect, useState } from 'react';
import './StubPages.css';

const API_URL = 'http://localhost:5000/api';

const AppointmentHistory = ({ onNavigate }) => {
  const [appointments, setAppointments] = useState([]);
  const [filteredAppointments, setFilteredAppointments] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('All');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchAppointments();
  }, []);

  const fetchAppointments = async () => {
    try {
      setLoading(true);
      setError('');

      const response = await fetch(`${API_URL}/appointments`);
      const result = await response.json();

      if (result.success) {
        // Sort appointments by date (newest first)
        const sorted = (result.data || []).sort((a, b) =>
          new Date(b.appointmentDate) - new Date(a.appointmentDate)
        );
        setAppointments(sorted);
        setFilteredAppointments(sorted);
      } else {
        setError(result.error || 'Failed to load appointments');
      }
    } catch (err) {
      console.error('Error:', err);
      setError('Unable to connect to server');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    const term = e.target.value.toLowerCase();
    setSearchTerm(term);
    applyFilters(term, filterStatus);
  };

  const handleStatusFilter = (e) => {
    const status = e.target.value;
    setFilterStatus(status);
    applyFilters(searchTerm, status);
  };

  const applyFilters = (search, status) => {
    let filtered = appointments;

    // Filter by search term
    if (search) {
      filtered = filtered.filter(apt =>
        apt.patientName?.toLowerCase().includes(search) ||
        apt.doctorName?.toLowerCase().includes(search) ||
        apt.reason?.toLowerCase().includes(search)
      );
    }

    // Filter by status
    if (status !== 'All') {
      filtered = filtered.filter(apt => apt.status === status);
    }

    setFilteredAppointments(filtered);
  };

  const cancelAppointment = async (appointmentId) => {
    if (window.confirm('Are you sure you want to cancel this appointment?')) {
      try {
        const response = await fetch(`${API_URL}/appointments/${appointmentId}`, {
          method: 'DELETE',
        });

        const result = await response.json();

        if (result.success) {
          fetchAppointments();
        } else {
          alert(result.error || 'Failed to cancel appointment');
        }
      } catch (err) {
        console.error('Error:', err);
        alert('Unable to cancel appointment');
      }
    }
  };

  const getStatusColor = (status) => {
    const colors = {
      'Confirmed': '#4caf50',
      'Pending': '#ff9800',
      'Completed': '#4a90e2',
      'Cancelled': '#f44336',
    };
    return colors[status] || '#999';
  };

  const getStatusBadgeClass = (status) => {
    return status.toLowerCase().replace(' ', '-');
  };

  if (loading) {
    return (
      <div className="page-wrapper">
        <div className="page-header">
          <h1>📅 Appointment History</h1>
        </div>
        <div className="loading-state">
          <div className="spinner"></div>
          <p>Loading appointments...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="page-wrapper">
      <div className="page-header">
        <h1>📅 Appointment History</h1>
        <p>All patient appointments and their status</p>
      </div>

      {error && (
        <div className="error-message">
          <span>⚠️</span>
          <p>{error}</p>
          <button onClick={fetchAppointments} className="retry-btn">Retry</button>
        </div>
      )}

      <div className="page-content">
        <div className="filter-bar">
          <input
            type="search"
            placeholder="Search by patient, doctor, or reason..."
            className="search-input"
            value={searchTerm}
            onChange={handleSearch}
          />
          <select
            className="filter-select"
            value={filterStatus}
            onChange={handleStatusFilter}
          >
            <option value="All">All Status</option>
            <option value="Pending">Pending</option>
            <option value="Confirmed">Confirmed</option>
            <option value="Completed">Completed</option>
            <option value="Cancelled">Cancelled</option>
          </select>
          <button className="btn-add" onClick={() => onNavigate('book-appointment')}>
            + New Appointment
          </button>
        </div>

        {filteredAppointments.length === 0 ? (
          <div className="empty-state">
            <p>❌ No appointments found</p>
            {appointments.length === 0 ? (
              <button className="btn-add" onClick={() => onNavigate('book-appointment')}>
                Book First Appointment
              </button>
            ) : (
              <p>Try adjusting your search or filter</p>
            )}
          </div>
        ) : (
          <div className="table-wrapper">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Patient</th>
                  <th>Doctor</th>
                  <th>Date & Time</th>
                  <th>Reason</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredAppointments.map((apt) => (
                  <tr key={apt.id}>
                    <td>
                      <div className="patient-name-cell">
                        <div className="patient-avatar-small">
                          {apt.patientName?.[0] || '?'}
                        </div>
                        <span>{apt.patientName || 'Unknown'}</span>
                      </div>
                    </td>
                    <td>Dr. {apt.doctorName || 'Unknown'}</td>
                    <td>
                      {new Date(apt.appointmentDate).toLocaleDateString()} @ {apt.appointmentTime}
                    </td>
                    <td>{apt.reason || 'N/A'}</td>
                    <td>
                      <span
                        className={`status-badge ${getStatusBadgeClass(apt.status)}`}
                        style={{ backgroundColor: getStatusColor(apt.status) }}
                      >
                        {apt.status}
                      </span>
                    </td>
                    <td>
                      <div className="action-buttons-cell">
                        {apt.status === 'Confirmed' && (
                          <button
                            className="action-link"
                            onClick={() => cancelAppointment(apt.id)}
                            title="Cancel this appointment"
                          >
                            Cancel
                          </button>
                        )}
                        {apt.status === 'Cancelled' && (
                          <span className="action-text-disabled">Cancelled</span>
                        )}
                        {apt.status === 'Completed' && (
                          <span className="action-text-success">✓ Done</span>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        <div className="stats-summary">
          <div className="summary-item">
            <span>Total Appointments:</span>
            <strong>{appointments.length}</strong>
          </div>
          <div className="summary-item">
            <span>Showing:</span>
            <strong>{filteredAppointments.length}</strong>
          </div>
          <div className="summary-item">
            <span>Confirmed:</span>
            <strong style={{ color: getStatusColor('Confirmed') }}>
              {appointments.filter(a => a.status === 'Confirmed').length}
            </strong>
          </div>
          <div className="summary-item">
            <span>Completed:</span>
            <strong style={{ color: getStatusColor('Completed') }}>
              {appointments.filter(a => a.status === 'Completed').length}
            </strong>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AppointmentHistory;
